@Override
public int compare(Double o1, Double o2) {
    if (o1 == null && o2 == null) {
        return 0;
    } else if (o1 == null) {
        return -1;
    } else if (o2 == null) {
        return 1;
    }
    // Tolerance for floating point comparison
    double epsilon = 0.000001;
    double diff = o1 - o2;
    if (Math.abs(diff) < epsilon) {
        // o1 and o2 are considered equal
        return 0;
    } else if (diff < 0) {
        // o1 is less than o2
        return -1;
    } else {
        // o1 is greater than o2
        return 1;
    }
}

