    if (value == null) {
        return dEfault;
    }
    String lowerCaseValue = value.toLowerCase();
    if (lowerCaseValue.equals("true")) {
        return true;
    } else if (lowerCaseValue.equals("false")) {
        return false;
    } else {
        return dEfault;
    }
}

