        return 0;
    } else if (aObj1 == null) {
        return -1;
    } else if (aObj2 == null) {
        return 1;
    } else {
        // Assuming the objects are comparable, cast them to Comparable and compare
        if (aObj1 instanceof Comparable && aObj2 instanceof Comparable) {
