/**
 * @return यदि बकेट समान है तो true लौटाता है।
 */
public static boolean isCompatible(DataTable dataset) {
    Map<String, Integer> bucketCounts = dataset.getBucketCounts();
    if (bucketCounts.isEmpty()) {
        return true;
    }
    int firstCount = bucketCounts.values().iterator().next();
    for (int count : bucketCounts.values()) {
        if (count != firstCount) {
            return false;
        }
    }
    return true;
}

/**
 * @param dataset the dataset to check for bucket compatibility
 * @return true if the buckets are compatible, false otherwise
 */
public boolean isCompatible(DataTable dataset) {
    if (dataset == null) {
        return false;
    }
    // Assuming DataTable has a method getBuckets() that returns an array of buckets
    Bucket[] buckets = dataset.getBuckets();
    if (buckets == null || buckets.length == 0) {
        return false;
    }
    // Compare all buckets to the first one
    Bucket firstBucket = buckets[0];
    for (Bucket bucket : buckets) {
        if (!Objects.equals(bucket, firstBucket)) {
            return false;
        }
    }
    return true;
}

/**
 * @param dataset डेटा टेबल जिसकी जांच की जानी है
 * @return यदि बकेट समान है तो true लौटाता है।
 */
public boolean isCompatible(DataTable dataset) {
    // Assuming DataTable has a method getBucket() that returns the bucket identifier
    String bucket1 = dataset.getBucket();
    // Assuming this class has a getBucket() method
    String bucket2 = this.getBucket();
    // Compare the two buckets
    return Objects.equals(bucket1, bucket2);
}

/**
 * @param dataset the dataset to check for bucket compatibility
 * @return true if the buckets are compatible, false otherwise
 */
public boolean isCompatible(DataTable dataset) {
    if (dataset == null) {
        return false;
    }
    // Assuming DataTable has a method getBuckets() that returns a list of buckets
    List<Bucket> buckets = dataset.getBuckets();
    if (buckets == null || buckets.isEmpty()) {
        return false;
    }
    // Get the first bucket to compare with the rest
    Bucket firstBucket = buckets.get(0);
    for (Bucket bucket : buckets) {
        if (!Objects.equals(firstBucket, bucket)) {
            return false;
        }
    }
    return true;
}

/**
 * @return यदि बकेट समान है तो true लौटाता है।
 */
public boolean isCompatible(DataTable dataset) {
    if (dataset == null || dataset.getData() == null || dataset.getData().isEmpty()) {
        return false;
    }
    // Assuming compatibility is determined by checking if all rows have the same set of keys
    Map<String, Object> firstRow = dataset.getData().get(0);
    for (Map<String, Object> row : dataset.getData()) {
        if (!row.keySet().equals(firstRow.keySet())) {
